    12→func TestTransflowEndToEndIntegration(t *testing.T) {
    13→	// Skip integration tests in short mode
    14→	if testing.Short() {
    15→		t.Skip("skipping integration test in short mode")
    16→	}
    17→
    18→	tests := []struct {
    19→		name        string
    20→		config      *TransflowConfig
    21→		testMode    bool
    22→		expectError bool
    23→	}{
    24→		{
    25→			name: "successful_workflow_with_mocks",
    26→			config: &TransflowConfig{
    27→				Version:      "v1alpha1",
    28→				ID:           "test-integration-success",
    29→				TargetRepo:   "https://gitlab.com/iw2rmb/ploy-orw-java11-maven.git",
    30→				TargetBranch: "main",
    31→				BaseRef:      "main",
    32→				Lane:         "C",
    33→				BuildTimeout: "10m",
    34→				Steps: []TransflowStep{
    35→					{
    36→						Type:    "recipe",
    37→						ID:      "test-recipe",
    38→						Engine:  "openrewrite",
    39→						Recipes: []string{"org.openrewrite.java.format.AutoFormat"},
    40→					},
    41→				},
    42→				SelfHeal: GetDefaultSelfHealConfig(),
    43→			},
    44→			testMode:    true,
    45→			expectError: false,
    46→		},
    47→		{
    48→			name: "workflow_with_build_failure",
    49→			config: &TransflowConfig{
    50→				Version:      "v1alpha1",
    51→				ID:           "test-integration-fail",
    52→				TargetRepo:   "https://gitlab.com/iw2rmb/ploy-orw-java11-maven.git",
    53→				TargetBranch: "main",
    54→				BaseRef:      "main",
    55→				Lane:         "C",
    56→				BuildTimeout: "10m",
    57→				Steps: []TransflowStep{
    58→					{
    59→						Type:    "recipe",
    60→						ID:      "test-recipe",
    61→						Engine:  "openrewrite",
    62→						Recipes: []string{"org.openrewrite.java.format.AutoFormat"},
    63→					},
    64→				},
    65→				SelfHeal: GetDefaultSelfHealConfig(),
    66→			},
    67→			testMode:    true, // We'll configure mock to fail
    68→			expectError: true,
    69→		},
    70→	}
    71→
    72→	for _, tt := range tests {
    73→		t.Run(tt.name, func(t *testing.T) {
    74→			// Create temporary workspace
    75→			workspaceDir, err := os.MkdirTemp("", "transflow-integration-test-*")
    76→			if err != nil {
    77→				t.Fatalf("failed to create temp directory: %v", err)
    78→			}
    79→			defer os.RemoveAll(workspaceDir)
    80→
    81→			// Create integrations with test mode
    82→			integrations := NewTransflowIntegrationsWithTestMode("http://localhost:8080", workspaceDir, tt.testMode)
    83→
    84→			// For build failure test, override with failing mock
    85→			if tt.name == "workflow_with_build_failure" {
    86→				integrations.TestMode = true
    87→				failingIntegrations := &TransflowIntegrations{
    88→					ControllerURL: integrations.ControllerURL,
    89→					WorkDir:       integrations.WorkDir,
    90→					TestMode:      true,
    91→				}
    92→				// This will test the failure path
    93→				runner, err := failingIntegrations.CreateConfiguredRunner(tt.config)
    94→				if err != nil {
    95→					t.Fatalf("failed to create runner: %v", err)
    96→				}
    97→
    98→				// Override with failing build checker
    99→				runner.SetBuildChecker(NewTestModeBuildChecker(true))
   100→
   101→				// Execute workflow
   102→				ctx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
   103→				defer cancel()
   104→
   105→				result, err := runner.Run(ctx)
   106→				if !tt.expectError {
   107→					t.Errorf("expected error but got none, result: %v", result)
   108→				}
   109→				if err == nil {
   110→					t.Error("expected error but workflow succeeded")
   111→				}
   112→				return
   113→			}
   114→
   115→			// Create configured runner
   116→			runner, err := integrations.CreateConfiguredRunner(tt.config)
   117→			if err != nil {
   118→				t.Fatalf("failed to create runner: %v", err)
   119→			}
   120→
   121→			// Set environment for GitLab integration testing
   122→			os.Setenv("GITLAB_TOKEN", "test-token-for-integration")
   123→			defer os.Unsetenv("GITLAB_TOKEN")
   124→
   125→			// Execute workflow
   126→			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
   127→			defer cancel()
   128→
   129→			result, err := runner.Run(ctx)
   130→
   131→			// Verify results
   132→			if tt.expectError {
   133→				if err == nil {
   134→					t.Error("expected error but workflow succeeded")
   135→				}
   136→				return
   137→			}
   138→
   139→			if err != nil {
   140→				t.Fatalf("workflow failed unexpectedly: %v", err)
   141→			}
   142→
   143→			if result == nil {
   144→				t.Fatal("expected result but got nil")
   145→			}
   146→
   147→			// Verify workflow components
   148→			if result.BranchName == "" {
   149→				t.Error("expected branch name but got empty string")
   150→			}
   151→
   152→			if result.BuildVersion == "" {
   153→				t.Error("expected build version but got empty string")
   154→			}
   155→
   156→			// Check that all expected steps completed
   157→			expectedSteps := []string{"clone", "create-branch", "test-recipe", "commit", "build", "push", "mr"}
   158→			if len(result.StepResults) < len(expectedSteps) {
   159→				t.Errorf("expected at least %d steps but got %d", len(expectedSteps), len(result.StepResults))
   160→			}
   161→
   162→			// Verify all steps succeeded
   163→			for _, stepResult := range result.StepResults {
   164→				if !stepResult.Success {
   165→					t.Errorf("step %s failed: %s", stepResult.StepID, stepResult.Message)
   166→				}
   167→			}
   168→
   169→			// Verify workspace was used
   170→			if _, err := os.Stat(workspaceDir); os.IsNotExist(err) {
   171→				t.Error("workspace directory was not created")
   172→			}
   173→
   174→			t.Logf("Workflow completed successfully:")
   175→			t.Logf("  Branch: %s", result.BranchName)
   176→			t.Logf("  Build: %s", result.BuildVersion)
   177→			t.Logf("  Steps: %d completed", len(result.StepResults))
   178→		})
   179→	}
   180→}
