   182→func TestTransflowConfigurationValidation(t *testing.T) {
   183→	tests := []struct {
   184→		name        string
   185→		config      *TransflowConfig
   186→		expectError bool
   187→	}{
   188→		{
   189→			name: "valid_minimal_config",
   190→			config: &TransflowConfig{
   191→				Version:      "v1alpha1",
   192→				ID:           "test-valid",
   193→				TargetRepo:   "https://gitlab.com/iw2rmb/ploy-orw-java11-maven.git",
   194→				TargetBranch: "main",
   195→				BaseRef:      "main",
   196→				Steps: []TransflowStep{
   197→					{
   198→						Type:    "recipe",
   199→						ID:      "test",
   200→						Engine:  "openrewrite",
   201→						Recipes: []string{"org.test.Recipe"},
   202→					},
   203→				},
   204→			},
   205→			expectError: false,
   206→		},
   207→		{
   208→			name: "missing_required_fields",
   209→			config: &TransflowConfig{
   210→				Version: "v1alpha1",
   211→				// Missing ID, TargetRepo, etc.
   212→			},
   213→			expectError: true,
   214→		},
   215→		{
   216→			name: "invalid_build_timeout",
   217→			config: &TransflowConfig{
   218→				Version:      "v1alpha1",
   219→				ID:           "test-timeout",
   220→				TargetRepo:   "https://gitlab.com/iw2rmb/ploy-orw-java11-maven.git",
   221→				TargetBranch: "main",
   222→				BaseRef:      "main",
   223→				BuildTimeout: "invalid-timeout",
   224→				Steps: []TransflowStep{
   225→					{
   226→						Type:    "recipe",
   227→						ID:      "test",
   228→						Engine:  "openrewrite",
   229→						Recipes: []string{"org.test.Recipe"},
   230→					},
   231→				},
   232→			},
   233→			expectError: true,
   234→		},
   235→	}
   236→
   237→	for _, tt := range tests {
   238→		t.Run(tt.name, func(t *testing.T) {
   239→			err := tt.config.Validate()
   240→
   241→			if tt.expectError {
   242→				if err == nil {
   243→					t.Error("expected validation error but got none")
   244→				}
   245→			} else {
   246→				if err != nil {
   247→					t.Errorf("expected no validation error but got: %v", err)
   248→				}
   249→			}
   250→		})
   251→	}
   252→}
