   254→func TestTransflowIntegrationsFactory(t *testing.T) {
   255→	workspaceDir, err := os.MkdirTemp("", "transflow-factory-test-*")
   256→	if err != nil {
   257→		t.Fatalf("failed to create temp directory: %v", err)
   258→	}
   259→	defer os.RemoveAll(workspaceDir)
   260→
   261→	t.Run("production_mode_integrations", func(t *testing.T) {
   262→		integrations := NewTransflowIntegrationsWithTestMode("http://localhost:8080", workspaceDir, false)
   263→
   264→		if integrations.TestMode {
   265→			t.Error("expected TestMode to be false")
   266→		}
   267→
   268→		// Test that production implementations are created
   269→		gitOps := integrations.CreateGitOperations()
   270→		if gitOps == nil {
   271→			t.Error("expected git operations but got nil")
   272→		}
   273→
   274→		recipeExec := integrations.CreateRecipeExecutor()
   275→		if recipeExec == nil {
   276→			t.Error("expected recipe executor but got nil")
   277→		}
   278→
   279→		buildChecker := integrations.CreateBuildChecker()
   280→		if buildChecker == nil {
   281→			t.Error("expected build checker but got nil")
   282→		}
   283→
   284→		gitProvider := integrations.CreateGitProvider()
   285→		if gitProvider == nil {
   286→			t.Error("expected git provider but got nil")
   287→		}
   288→	})
   289→
   290→	t.Run("test_mode_integrations", func(t *testing.T) {
   291→		integrations := NewTransflowIntegrationsWithTestMode("http://localhost:8080", workspaceDir, true)
   292→
   293→		if !integrations.TestMode {
   294→			t.Error("expected TestMode to be true")
   295→		}
   296→
   297→		// Test that mock implementations are created for testable components
   298→		buildChecker := integrations.CreateBuildChecker()
   299→		if buildChecker == nil {
   300→			t.Error("expected build checker but got nil")
   301→		}
   302→
   303→		// Verify it's a mock by testing behavior
   304→		ctx := context.Background()
   305→		result, err := buildChecker.CheckBuild(ctx, common.DeployConfig{
   306→			App:         "test-app",
   307→			Lane:        "C",
   308→			Environment: "dev",
   309→		})
   310→
   311→		if err != nil {
   312→			t.Errorf("mock build checker should not fail: %v", err)
   313→		}
   314→
   315→		if result == nil || !result.Success {
   316→			t.Error("mock build checker should return successful result")
   317→		}
   318→
   319→		// Test mock git provider
   320→		gitProvider := integrations.CreateGitProvider()
   321→		if gitProvider == nil {
   322→			t.Error("expected git provider but got nil")
   323→		}
   324→
   325→		// Verify it's a mock
   326→		if err := gitProvider.ValidateConfiguration(); err != nil {
   327→			t.Errorf("mock git provider validation should succeed: %v", err)
   328→		}
   329→	})
   330→}
